import React, { useState } from "react";

function SOP() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule1 = async () => {
    setLoading(true);
    try {
      const res = await fetch("http://localhost:5000/module1");
      const data = await res.json();
      setResult(data);
    } catch (error) {
      alert("Backend error");
    }
    setLoading(false);
  };

  const data = result?.data;

  return (
    <div style={{ textAlign: "center", marginTop: "20px" }}>
      <button onClick={runModule1}>Run Module 1</button>

      {loading && <p>Processing...</p>}

      {result?.status === "success" && data && (
        <div>
          <h3>Output</h3>
          <p>NPSV Length: {data.npsv_length ?? "N/A"}</p>

          <p>
            Segments Shape:{" "}
            {data?.segments_shape?.length
              ? data.segments_shape.join(", ")
              : "Not available"}
          </p>
        </div>
      )}
    </div>
  );
}

export default SOP;
